mapper.sql:
(
    select mo.apt_cmplex_no
    from mgmt_office mo
    where mo.mgmt_ofc_no = #{mgmtOfcNo}
)

mapper.select:
select apt_cmplex_no
from mgmt_office
where mgmt_ofc_no = #{mgmtOfcNo}

select x.cmn_facility_no , x.apt_cmplex_no , x.facility_no , x.cmn_facility_nm , x.cmn_facility_cn , x.cmn_facility_amt , x.cmn_facility_rsv_yn , x.cmn_facility_opr_hr , x.reg_dt , x.mdf_dt , x.facility_nm , x.facility_ty_cd , x.facility_ty_nm , x.instl_dt , x.dong_no , x.dong_nm , x.loc_cn , x.use_yn , x.file_group_no , x.item_cnt , x.repair_cnt , x.close_cnt , x.oper_status from ( select pf.cmn_facility_no , f.apt_cmplex_no , f.facility_no , nvl(pf.cmn_facility_nm, f.facility_nm) as cmn_facility_nm , pf.cmn_facility_cn , pf.cmn_facility_amt , pf.cmn_facility_rsv_yn , pf.cmn_facility_opr_hr , to_char(pf.reg_dt, 'YYYY-MM-DD') as reg_dt , to_char(pf.mdf_dt, 'YYYY-MM-DD') as mdf_dt , f.facility_nm , f.facility_ty_cd , cc.code_name as facility_ty_nm , to_char(f.instl_dt, 'YYYY-MM-DD') as instl_dt , f.dong_no , au.dong_nm , f.loc_cn , nvl(f.use_yn, 'Y') as use_yn , f.file_group_no , nvl(pi.item_cnt, 0) as item_cnt , nvl(pi.repair_cnt, 0) as repair_cnt , nvl(pi.close_cnt, 0) as close_cnt , case when pf.cmn_facility_no is null then 'UNREGISTERED' when nvl(pi.close_cnt, 0) > 0 then 'CLOSE_PART' when nvl(pi.repair_cnt, 0) > 0 then 'REPAIR_PART' else 'NORMAL' end as oper_status from facility f left join public_facility pf on pf.facility_no = f.facility_no and pf.apt_cmplex_no = f.apt_cmplex_no left join common_code cc on cc.group_code_no = 'FACILITY_TY' and cc.code_no_cd = f.facility_ty_cd left join apt_unit au on au.dong_no = f.dong_no left join (
) pi on pi.cmn_facility_no = pf.cmn_facility_no where f.apt_cmplex_no = and f.facility_ty_cd in () and nvl(f.use_yn, 'Y') = 'Y' ) x
and ( lower(x.cmn_facility_nm) like '%' || lower(#{keyword}) || '%' or lower(x.facility_nm) like '%' || lower(#{keyword}) || '%' or lower(x.loc_cn) like '%' || lower(#{keyword}) || '%' or lower(x.cmn_facility_no) like '%' || lower(#{keyword}) || '%' or lower(x.facility_no) like '%' || lower(#{keyword}) || '%' )
and x.facility_ty_cd = #{facilityTyCd}
and x.dong_no = #{dongNo}
and x.dong_no is null
and x.loc_cn = #{locCn}
and x.cmn_facility_rsv_yn = #{rsvYn}
and ( x.cmn_facility_opr_hr like '%' || #{oprDay} || '%' or (#{oprDay} in ('월', '화', '수', '목', '금') and x.cmn_facility_opr_hr like '%평일%') or (#{oprDay} in ('토', '일') and x.cmn_facility_opr_hr like '%주말%') or (#{oprDay} in ('월', '화', '수', '목', '금', '토', '일') and x.cmn_facility_opr_hr like '%매일%') )
and x.oper_status = #{operStatus}
order by case when x.cmn_facility_no is null then 0 else 1 end , x.cmn_facility_no desc nulls last , x.reg_dt desc nulls last , x.mdf_dt desc nulls last , x.facility_nm asc

mapper.insert:
insert into facility (
                       facility_no
                     , facility_ty_cd
                     , instl_dt
                     , facility_nm
                     , apt_cmplex_no
                     , dong_no
                     , loc_cn
                     , use_yn
                     , file_group_no
) values (
           #{facilityNo}
         , #{facilityTyCd}
         , sysdate
         , #{facilityNm}
         , #{aptCmplexNo}
         , #{dongNo}
         , #{locCn}
         , nvl(#{useYn}, 'Y')
         , #{fileGroupNo}
         )

mapper.select:
select count(*)
from public_facility
where facility_no = #{facilityNo}

